            "    \"concept_relationships\": {\"enabled\": \"generate_concept_relationships\", \"file\": \"concept_relationships.json\", \"schema\": {\"type\": \"object\", \"required\": [\"items\"], \"properties\": {\"items\": {\"type\": \"array\", \"items\": {\"type\": \"object\", \"required\": [\"source\", \"target\", \"relationship\"], \"properties\": {\"source\": {\"type\": \"string\"}, \"target\": {\"type\": \"string\"}, \"relationship\": {\"type\": \"string\"}}}}}}},\n",
