    # 08_SVARA_JS_SCRIPT
    cells.append({
        "cell_type": "code",
        "execution_count": None,
        "metadata": {},
        "outputs": [],
        "source": [
            "svara_js_code = f\"\"\"\n",
            "import fs from 'node:fs';\n",
            "import path from 'node:path';\n",
            "import {{ performance }} from 'node:perf_hooks';\n",
            "import * as ort from 'onnxruntime-node';\n",
            "import {{ AutoModelForCausalLM, AutoTokenizer, Tensor }} from '@huggingface/transformers';\n",
            "\n",
            "const VOICE_PACK_JSON = '{PACK_ROOT}/voice_pack.json';\n",
            "const AUDIO_DIR = '{AUDIO_ROOT}';\n",
            "const MODEL_ID = 'shreyask/svara-tts-v1-ONNX';\n",
            "const SNAC_DECODER = '{snac_decoder_path}';\n",
            "const SAMPLE_RATE = 24000;\n",
            "\n",
            "function wavBuffer(floatSamples, sampleRate) {{\n",
            "  const n = floatSamples.length;\n",
            "  const buffer = Buffer.alloc(44 + n * 2);\n",
            "  buffer.write('RIFF', 0);\n",
            "  buffer.writeUInt32LE(36 + n * 2, 4);\n",
            "  buffer.write('WAVE', 8);\n",
            "  buffer.write('fmt ', 12);\n",
            "  buffer.writeUInt32LE(16, 16);\n",
            "  buffer.writeUInt16LE(1, 20);\n",
            "  buffer.writeUInt16LE(1, 22);\n",
            "  buffer.writeUInt32LE(sampleRate, 24);\n",
            "  buffer.writeUInt32LE(sampleRate * 2, 28);\n",
            "  buffer.writeUInt16LE(2, 32);\n",
            "  buffer.writeUInt16LE(16, 34);\n",
            "  buffer.write('data', 36);\n",
            "  buffer.writeUInt32LE(n * 2, 40);\n",
            "  for (let i = 0; i < n; i++) {{\n",
            "    const clamped = Math.max(-1, Math.min(1, Number(floatSamples[i])));\n",
            "    buffer.writeInt16LE(Math.round(clamped * 32767), 44 + i * 2);\n",
            "  }}\n",
            "  return buffer;\n",
            "}}\n",
            "\n",
            "function extractSnacCodes(fullOutput, inputLength) {{\n",
            "  const generated = fullOutput.slice(inputLength).map(Number);\n",
            "  const sosIndex = generated.indexOf(128257);\n",
            "  const start = sosIndex >= 0 ? sosIndex + 1 : 0;\n",
            "  const audio = [];\n",
            "  let bandPos = 0;\n",
            "  for (const token of generated.slice(start)) {{\n",
            "    if (token === 128258) break;\n",
            "    if (token < 128266 || token >= 156938) continue;\n",
            "    const band = bandPos % 7;\n",
            "    const code = token - 128266 - band * 4096;\n",
            "    if (code >= 0 && code < 4096) {{\n",
            "      audio.push({{ band, code }});\n",
            "      bandPos += 1;\n",
            "    }}\n",
            "  }}\n",
            "  const frameCount = Math.floor(audio.length / 7);\n",
            "  const level0 = []; const level1 = []; const level2 = [];\n",
            "  for (let frame = 0; frame < frameCount; frame++) {{\n",
            "    const codes = audio.slice(frame * 7, frame * 7 + 7).map((x) => x.code);\n",
            "    level0.push(codes[0]); level1.push(codes[1], codes[4]); level2.push(codes[2], codes[3], codes[5], codes[6]);\n",
            "  }}\n",
            "  return {{ frameCount, level0, level1, level2 }};\n",
            "}}\n",
            "\n",
            "async function decodeSnac(decoder, codes) {{\n",
            "  if (codes.frameCount < 1) throw new Error('No SNAC frame generated.');\n",
            "  const feeds = {{\n",
            "    'audio_codes.0': new ort.Tensor('int64', BigInt64Array.from(codes.level0.map(BigInt)), [1, codes.level0.length]),\n",
            "    'audio_codes.1': new ort.Tensor('int64', BigInt64Array.from(codes.level1.map(BigInt)), [1, codes.level1.length]),\n",
            "    'audio_codes.2': new ort.Tensor('int64', BigInt64Array.from(codes.level2.map(BigInt)), [1, codes.level2.length]),\n",
            "  }};\n",
            "  const output = await decoder.run(feeds);\n",
            "  return output.audio_values.data;\n",
            "}}\n",
            "\n",
            "async function main() {{\n",
            "  if (!fs.existsSync(VOICE_PACK_JSON)) {{\n",
            "    console.log('No voice pack json found, skipping audio generation.');\n",
            "    return;\n",
            "  }}\n",
            "  const voicePackData = JSON.parse(fs.readFileSync(VOICE_PACK_JSON, 'utf-8'));\n",
            "  let itemsToGenerate = [];\n",
            "  voicePackData.forEach((section, s_idx) => {{\n",
            "    const payloadItems = (section.payload && section.payload.items) ? section.payload.items : [];\n",
            "    payloadItems.forEach((item, i_idx) => {{\n",
            "      itemsToGenerate.push({{\n",
            "        section_id: section.section_id,\n",
            "        item_index: i_idx,\n",
            "        speaker: item.speaker || 'English (Indian) (Female)',\n",
            "        dialogue: item.dialogue || ''\n",
            "      }});\n",
            "    }});\n",
            "  }});\n",
            "  \n",
            "  console.log(`Loading Svara TTS model...`);\n",
            "  const tokenizer = await AutoTokenizer.from_pretrained(MODEL_ID);\n",
            "  const model = await AutoModelForCausalLM.from_pretrained(MODEL_ID, {{\n",
            "    dtype: 'q4f16', device: 'cpu', use_external_data_format: true,\n",
            "  }});\n",
            "  const decoder = await ort.InferenceSession.create(SNAC_DECODER, {{ executionProviders: ['cpu'] }});\n",
            "  \n",
            "  for (const item of itemsToGenerate) {{\n",
            "    if (!item.dialogue) continue;\n",
            "    const audioFile = path.join(AUDIO_DIR, `${{item.section_id}}_${{item.item_index}}.wav`);\n",
            "    if (fs.existsSync(audioFile)) continue; // Cache support for audio!\n",
            "    console.log(`Generating audio for ${{item.section_id}} [${{item.item_index}}]...`);\n",
            "    try {{\n",
            "      const body = tokenizer.encode(`${{item.speaker}}: ${{item.dialogue}}`, {{ add_special_tokens: false }});\n",
            "      const ids = [128259, tokenizer.bos_token_id, ...body, 128009, 128260];\n",
            "      const out = await model.generate({{\n",
            "        inputs: new Tensor('int64', BigInt64Array.from(ids.map(BigInt)), [1, ids.length]),\n",
            "        max_new_tokens: 180,\n",
            "        do_sample: true,\n",
            "        temperature: 0.6,\n",
            "        top_p: 0.9,\n",
            "        top_k: 40,\n",
            "        eos_token_id: 128258,\n",
            "      }});\n",
            "      const codes = extractSnacCodes(Array.from(out.data), ids.length);\n",
            "      const audio = await decodeSnac(decoder, codes);\n",
            "      fs.writeFileSync(audioFile, wavBuffer(audio, SAMPLE_RATE));\n",
            "      console.log(`  -> Saved ${{audioFile}}`);\n",
            "    }} catch (error) {{\n",
            "      console.error(`  -> Failed:`, error.message);\n",
            "    }}\n",
            "  }}\n",
            "}}\n",
            "main().catch(console.error);\n",
            "\"\"\"\n",
            "\n",
            "with open(OUTPUT_ROOT / \"generate_audio.mjs\", \"w\") as f:\n",
            "    f.write(svara_js_code)\n",
            "\n",
            "!node {OUTPUT_ROOT}/generate_audio.mjs\n"
        ]
    })

    # 09_FINAL_ZIP
    cells.append({
        "cell_type": "code",
        "execution_count": None,
        "metadata": {},
        "outputs": [],
        "source": [
            "zip_path = OUTPUT_ROOT / CONFIG[\"artifact_zip_name\"]\n",
            "with zipfile.ZipFile(zip_path, \"w\", zipfile.ZIP_DEFLATED) as archive:\n",
            "    # Add all JSON artifacts\n",
            "    for file_path in PACK_ROOT.rglob(\"*.json\"):\n",
            "        archive.write(file_path, arcname=str(file_path.relative_to(PACK_ROOT.parent)))\n",
            "    # Add all Audio artifacts\n",
            "    for file_path in AUDIO_ROOT.rglob(\"*.wav\"):\n",
            "        archive.write(file_path, arcname=str(file_path.relative_to(PACK_ROOT.parent)))\n",
            "print(\"Process complete. Final zip saved to\", zip_path)\n"
        ]
    })
    
